// Helper: get keywords for a route (supports wildcard /:param matching)
export function getKeywordsForRoute(pathname: string): string {
  // Direct match
  if (routeKeywords[pathname]) {
    return routeKeywords[pathname].join(", ");
  }

  // Try pattern matching for /:id routes
  // e.g., /destinations/usa → match /destinations/:destId fallback
  const segments = pathname.split("/").filter(Boolean);
  if (segments.length >= 2) {
    const parentRoute = "/" + segments[0];
    if (routeKeywords[parentRoute]) {
      return routeKeywords[parentRoute].join(", ");
    }
  }

  // Default: all keywords combined (truncated)
  const allKeywords = Object.values(routeKeywords).flat();
  const unique = [...new Set(allKeywords)];
  return unique.slice(0, 30).join(", ");
}

// All keywords for sitemap/indexing purposes
export const allKeywords = Object.values(routeKeywords).flat();
export const uniqueKeywords = [...new Set(allKeywords)];
